import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import ProjectList from '../components/Projects/ProjectList';
import TaskList from '../components/Tasks/TaskList';
import '../styles/Dashboard.css';

const Dashboard = () => {
  const { currentUser } = useAuth();
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);

        // In a real app, you would fetch this data from your API
        // For now, we'll use empty arrays as initial state
        setProjects([]);
        setTasks([]);
        setUsers(currentUser ? [currentUser] : []);

      } catch (err) {
        console.error('Error fetching dashboard data:', err);
        setError('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [currentUser]);

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen">
        <div className="loading-pulse">
          <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-4 bg-red-100 border border-red-400 text-red-700 rounded">
        <p>{error}</p>
      </div>
    );
  }

  const stats = {
    totalProjects: projects.length,
    totalTasks: tasks.length,
    completedTasks: tasks.filter(task => task.status === 'Completed').length,
    inProgressTasks: tasks.filter(task => task.status === 'In Progress').length,
    myTasks: tasks.filter(task => task.assignee_id === currentUser?.id).length
  };

  const recentTasks = tasks.slice(0, 5);
  const myRecentTasks = tasks
    .filter(task => task.assignee_id === currentUser?.id)
    .slice(0, 3);

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Welcome back, {currentUser?.name || 'User'}! 👋</h1>
        <p>Here's what's happening with your projects today.</p>
      </div>

      {/* Statistics Grid */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">📁</div>
          <div className="stat-content">
            <h3>{stats.totalProjects}</h3>
            <p>Total Projects</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-content">
            <h3>{stats.totalTasks}</h3>
            <p>Total Tasks</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🚀</div>
          <div className="stat-content">
            <h3>{stats.inProgressTasks}</h3>
            <p>In Progress</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🎯</div>
          <div className="stat-content">
            <h3>{stats.myTasks}</h3>
            <p>My Tasks</p>
          </div>
        </div>
      </div>

      <div className="dashboard-content">
        {/* My Recent Tasks */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>My Recent Tasks</h2>
            <button 
              onClick={() => navigate('/my-tasks')}
              className="btn btn-outline"
            >
              View All
            </button>
          </div>
          {myRecentTasks.length > 0 ? (
            <TaskList tasks={myRecentTasks} users={users} projects={projects} />
          ) : (
            <div className="empty-state">
              <p>No tasks assigned to you yet</p>
              <button 
                onClick={() => navigate('/tasks/new')}
                className="btn btn-primary mt-4"
              >
                Create your first task
              </button>
            </div>
          )}
        </section>

        {/* All Projects */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>All Projects</h2>
            <span className="project-count">{projects.length} projects</span>
          </div>
          {projects.length > 0 ? (
            <ProjectList projects={projects} users={users} />
          ) : (
            <div className="empty-state">
              <p>No projects created yet</p>
              <button 
                onClick={() => navigate('/projects/new')}
                className="btn btn-primary mt-4"
              >
                Create your first project
              </button>
            </div>
          )}
        </section>
      </div>

      {/* Recent Activity */}
      <section className="dashboard-section mt-8">
        <div className="section-header">
          <h2>Recent Activity</h2>
        </div>
        <div className="activity-list">
          <div className="activity-item">
            <div className="activity-icon">➕</div>
            <div className="activity-content">
              <p>Welcome to TaskTrail! Get started by creating your first project.</p>
              <span className="activity-time">Just now</span>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Dashboard;
